      "id": "spas-personal-assistance",
      "name": "State Personal Assistance Services (SPAS) Program",
      "shortName": "SPAS Program",
      "tagline": "Personal care assistance and home modifications for adults with disabilities to stay in their community",
      "programType": "benefit",
